import { useState, useEffect } from "react";
import { useNavigate, useParams, useLocation } from "react-router-dom";
import { useCart } from "../context/CartContext";
import { useLang } from "../context/LangContext";
import db from "../database.json";
import "../styles/Product.css";

function Product() {
  const [search, setSearch] = useState("");
  const [sortBy, setSortBy] = useState("");
  const [orderHistory, setOrderHistory] = useState([]);
  const [showHistory, setShowHistory] = useState(false);
  
  const navigate = useNavigate();
  const { category } = useParams();
  const location = useLocation();
  const { addToCart } = useCart();
  const { t } = useLang();

  // Load order history from localStorage
  useEffect(() => {
    const savedHistory = localStorage.getItem("orderHistory");
    if (savedHistory) {
      setOrderHistory(JSON.parse(savedHistory));
    }
  }, []);

  // Đọc search từ URL khi vào trang
  useEffect(() => {
    const params = new URLSearchParams(location.search);
    const q = params.get("search");
    if (q) setSearch(q);
    else setSearch("");
  }, [location.search]);

  const categoryNames = {
    "ngu-coc": `🌾 ${t.nguCoc}`,
    "banh-mi": `🍞 ${t.banhMi}`,
    "sua-trung": `🥛 ${t.suaTrung}`,
    "thit": `🥩 ${t.thit}`,
    "hai-san": `🦐 ${t.haiSan}`,
    "rau-cu": `🥦 ${t.rauCu}`,
    "trai-cay": `🍎 ${t.traiCay}`,
  };

  let products = category
    ? db.products.filter((p) => p.category === category)
    : [...db.products];

  if (search) {
    products = products.filter((p) =>
      p.title.toLowerCase().includes(search.toLowerCase())
    );
  }

  if (sortBy === "title-az") products.sort((a, b) => a.title.localeCompare(b.title));
  else if (sortBy === "title-za") products.sort((a, b) => b.title.localeCompare(a.title));
  else if (sortBy === "price-asc") products.sort((a, b) => a.price - b.price);
  else if (sortBy === "price-desc") products.sort((a, b) => b.price - a.price);

  const pageTitle = search
    ? `🔍 Kết quả tìm kiếm: "${search}"`
    : category
    ? categoryNames[category]
    : `🏪 ${t.allProducts}`;

  const handleCompleteOrder = (cartItems, totalAmount) => {
    const newOrder = {
      id: `ORD-${Date.now()}`,
      date: new Date().toLocaleString("vi-VN"),
      items: cartItems,
      total: totalAmount,
      status: "Đã thanh toán"
    };
    
    const updatedHistory = [newOrder, ...orderHistory];
    setOrderHistory(updatedHistory);
    localStorage.setItem("orderHistory", JSON.stringify(updatedHistory));
  };

  const downloadInvoice = (order) => {
    const invoiceContent = `
HÓAĐƠN MUA HÀNG
===============================
Mã đơn hàng: ${order.id}
Ngày: ${order.date}
Trạng thái: ${order.status}
===============================
CHI TIẾT SẢN PHẨM:
${order.items.map(item => 
  `- ${item.title} x${item.quantity}: ${(item.price * item.quantity).toLocaleString("vi-VN")}đ`
).join("\n")}
===============================
Tổng cộng: ${order.total.toLocaleString("vi-VN")}đ
===============================
Cảm ơn đã mua hàng!
    `;

    const element = document.createElement("a");
    element.setAttribute("href", "data:text/plain;charset=utf-8," + encodeURIComponent(invoiceContent));
    element.setAttribute("download", `${order.id}.txt`);
    element.style.display = "none";
    document.body.appendChild(element);
    element.click();
    document.body.removeChild(element);
  };

  return (
    <div className="product-page">
      <div className="product-container">
        {/* History Button */}
        <button 
          className="history-btn"
          onClick={() => setShowHistory(!showHistory)}
          title="Xem lịch sử hóa đơn"
        >
          📋 Lịch sử ({orderHistory.length})
        </button>

        {/* Order History Modal */}
        {showHistory && (
          <div className="history-modal">
            <div className="history-content">
              <div className="history-header">
                <h2>📋 Lịch sử đơn hàng</h2>
                <button 
                  className="close-btn"
                  onClick={() => setShowHistory(false)}
                >
                  ✕
                </button>
              </div>
              
              {orderHistory.length === 0 ? (
                <p className="empty-history">Chưa có đơn hàng nào</p>
              ) : (
                <div className="history-list">
                  {orderHistory.map((order) => (
                    <div key={order.id} className="history-item">
                      <div className="item-header">
                        <span className="order-id">{order.id}</span>
                        <span className="order-date">{order.date}</span>
                        <span className="order-status">{order.status}</span>
                      </div>
                      <div className="item-details">
                        {order.items.map((item, idx) => (
                          <div key={idx} className="item-product">
                            {item.title} x{item.quantity}: {(item.price * item.quantity).toLocaleString("vi-VN")}đ
                          </div>
                        ))}
                      </div>
                      <div className="item-footer">
                        <span className="total">Tổng: {order.total.toLocaleString("vi-VN")}đ</span>
                        <button 
                          className="download-invoice-btn"
                          onClick={() => downloadInvoice(order)}
                        >
                          📥 Tải hóa đơn
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        )}

        <h2 className="page-title">{pageTitle}</h2>

        {/* Controls */}
        <div className="controls">
          <input
            type="text"
            placeholder={t.search}
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="search-input"
          />
          <select
            value={sortBy}
            onChange={(e) => setSortBy(e.target.value)}
            className="sort-select"
          >
            <option value="">{t.sortBy}</option>
            <option value="title-az">{t.titleAZ}</option>
            <option value="title-za">{t.titleZA}</option>
            <option value="price-asc">{t.priceLow}</option>
            <option value="price-desc">{t.priceHigh}</option>
          </select>
          <span className="result-count">{products.length} {t.results}</span>
          {search && (
            <button
              className="clear-btn"
              onClick={() => {
                setSearch("");
                navigate("/products");
              }}
            >
              ✕ Xóa tìm kiếm
            </button>
          )}
        </div>

        {/* Grid */}
        {products.length === 0 ? (
          <div className="empty-state">
            <p className="empty-icon">😔</p>
            <p className="empty-text">{t.noProduct}</p>
            <button 
              className="back-btn" 
              onClick={() => { 
                setSearch(""); 
                navigate("/products"); 
              }}
            >
              ← {t.allProducts}
            </button>
          </div>
        ) : (
          <div className="products-grid">
            {products.map((product) => (
              <div key={product.id} className="product-card">
                <div className="image-box">
                  <img
                    src={product.image}
                    alt={product.title}
                    className="product-img"
                    onError={(e) => { e.target.src = "https://via.placeholder.com/200"; }}
                  />
                  {product.stock < 20 && (
                    <span className="low-stock-badge">{t.almostOut}</span>
                  )}
                </div>
                <div className="card-body">
                  <p className="product-category">{product.category.replace("-", " ").toUpperCase()}</p>
                  <h3 className="product-title">{product.title}</h3>
                  <div className="product-meta">
                    <span className="product-price">{product.price.toLocaleString("vi-VN")}đ</span>
                    <span className="product-stock">{t.remain} {product.stock}</span>
                  </div>
                  <div className="product-reviews">
                    {"⭐".repeat(Math.round(
                      product.reviews.reduce((s, r) => s + r.rating, 0) / (product.reviews.length || 1)
                    ))}
                    <span className="review-count">
                      ({product.reviews.length})
                    </span>
                  </div>
                  <div className="product-actions">
                    <button 
                      className="add-to-cart-btn" 
                      onClick={() => addToCart(product)}
                    >
                      {t.addCart}
                    </button>
                    <button 
                      className="detail-btn" 
                      onClick={() => navigate(`/detail/${product.id}`)}
                    >
                      {t.detail}
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

export default Product;
